import { client } from "@trigger.dev/sdk";
import { task } from "@trigger.dev/sdk";

// Initialize the Trigger.dev client
client.define({
  id: "progress-app",
});

// Define the progress task with dynamic trial_id
export const progressTask = task({
  id: "progress-task",
  displayName: "Progress Task",
  run: async (payload: { trialId: string }, { ctx }) => {
    const { trialId } = payload;
    const totalSteps = 5;

    console.log(`Starting progress task for trial ${trialId}`);

    // Simulate a long-running process with 5 steps
    for (let step = 1; step <= totalSteps; step++) {
      // Calculate progress percentage (0-100)
      const currentProgress = Math.round((step / totalSteps) * 100);

      console.log(`Step ${step}/${totalSteps} - Progress: ${currentProgress}%`);

      // Simulate some work (e.g., API call, data processing)
      await new Promise((resolve) => setTimeout(resolve, 1000));

      // Update the run metadata with current progress
      await ctx.run.updateMetadata({
        progress: currentProgress,
        step: step,
        totalSteps: totalSteps,
        trialId: trialId,
      });
    }

    console.log(`Progress task completed for trial ${trialId}`);

    return {
      success: true,
      trialId: trialId,
      finalProgress: 100,
    };
  },
});

